async function fieldsOf(collection) {
  if (!fieldsByCollection.has(collection)) {
    fieldsByCollection.set(collection, new Set((await api('GET', `/fields/${collection}`)).map((f) => f.field)))
  }
  return fieldsByCollection.get(collection)
